{"code": "import json, re, math
from collections import defaultdict

# Load the data
clinical_raw = locals()['var_functions.query_db:18']
expression_raw = locals()['var_functions.query_db:8']

# Load JSON data (if strings) or use directly
if isinstance(clinical_raw, str):
    clinical = json.loads(clinical_raw)
else:
    clinical = clinical_raw

if isinstance(expression_raw, str):
    expression = json.loads(expression_raw)
else:
    expression = expression_raw

# Process clinical data - extract barcodes and histological types
lgg_patients = []
for record in clinical:
    desc = record['Patient_description']
    # Find barcodes like TCGA-XX-XXXX, TCGA-XXXX, TCGA-XX-XXXXX
    matches = re.findall(r'TCGA-[A-Z0-9-]+', desc)
    if matches:
        lgg_patients.append([matches[0], record['histological_type']])

# Build expression dictionary
expr_dict = {}
for record in expression:
    expr_dict[record['ParticipantBarcode']] = float(record['normalized_count'])

# Join and compute log10 averages by histology
histology_data = defaultdict(list)
for barcode, hist_type in lgg_patients:
    if barcode in expr_dict:
        log_val = math.log10(expr_dict[barcode] + 1)
        histology_data[hist_type].append(log_val)

# Calculate averages
averages = {}
for hist_type in sorted(histology_data.keys()):
    vals = histology_data[hist_type]
    averages[hist_type] = sum(vals) / len(vals)

# Create output string
output_lines = []
for hist_type in sorted(averages.keys()):
    avg_val = averages[hist_type]
    output_lines.append(f"{hist_type}: {avg_val:.4f}")

result = "; ".join(output_lines)
print("__RESULT__:")
print(result)"}

